import java.util.PriorityQueue;
import java.util.List;

public int maxCoins(List<List<Integer>> piles, int k) {
    PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);
    for (List<Integer> pile : piles) {
        for (Integer coin : pile) {
            pq.offer(coin);
        }
    }

    int maxValue = 0;
    while (k > 0) {
        maxValue += pq.poll();
        k--;
    }
    return maxValue;
}
```

